'use strict';

var valid = [];

// Using a string literal:
var test = {
	'code': 'throw new Error( \'unexpected error.\' );'
};
valid.push( test );

// Using format function:
test = {
	'code': 'throw new Error( format( \'invalid argument. First argument must be a number. Value: `%s`.\', value ) );'
};
valid.push( test );

// Using a variable:
test = {
	'code': 'var msg = \'error message\';\nthrow new Error( msg );'
};
valid.push( test );

// Error constructor without arguments:
test = {
	'code': 'throw new Error();'
};
valid.push( test );

// TypeError with string literal:
test = {
	'code': 'throw new TypeError( \'expected a string.\' );'
};
valid.push( test );

// RangeError with format:
test = {
	'code': 'throw new RangeError( format( \'index out of bounds. Value: `%d`.\', idx ) );'
};
valid.push( test );


// EXPORTS //

module.exports = valid;
